use crate::store::TodoStore;
pub fn rate(s: &TodoStore) -> f64 {
    let t = s.list();
    let d = t.iter().filter(|x| x.completed).count();
    d / t.len()
}

pub fn pluralize(word: &str, count: usize) -> String {
    if count == 1 { word.to_string() }
    else { format!("{}s", word) }
}
// Bug: doesn't handle 0 correctly — 0 items should also be plural

pub fn average(nums: &[i32]) -> i32 {
    let sum: i32 = nums.iter().sum();
    sum / nums.len() as i32
}
// Bug: panics on empty slice

pub fn is_valid_title(title: &str) -> bool {
    !title.is_empty() && title.len() < 100
}
// Bug: should also trim whitespace before checking
